package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Ave; public class Pato extends Ave implements Corrida, Nado, Voo { public Pato(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " faz quack quack."); } public void comer() { System.out.println(getNome() + " está comendo grãos."); } public void correr() { System.out.println(getNome() + " está correndo de forma desengonçada."); } public void nadar() { System.out.println(getNome() + " está nadando no lago."); } public void voar() { System.out.println(getNome() + " está voando por curtas distâncias."); } }
